mapper.select:
SELECT c.vehicle_name, a.record_id, d.id case_id, d.testcase_content, a.is_successful, a.score, a.error_type, a.error_detail, a.other, a.test_status, a.case_type, e.plan_detail_name function_name, d.task_detail, d.tertiary_metric FROM `test_state` a, test_record b, vehicle c, test_case d, plan_detail e WHERE a.record_id = b.id AND b.vehicle_id = c.id AND d.id = a.testcase_id AND e.id = d.function_id AND d.scenario_id != 6
AND a.record_id in
#{vehicleId}
AND d.testcase_content LIKE CONCAT('%',#{testcaseContent},'%')
AND a.is_successful = #{isSuccessful}
AND a.score in
#{score}
AND a.test_status = #{testStatus}
AND e.plan_detail_name LIKE CONCAT('%',#{functionName},'%')
AND a.case_type = #{caseType}
AND a.error_type = #{errorType}
AND a.testcase_id = #{caseId}
AND d.tertiary_metric LIKE CONCAT('%',#{threeTag},'%')
AND( a.error_detail LIKE CONCAT('%',#{errorDetail},'%') or a.other LIKE CONCAT('%',#{errorDetail},'%'))
